            for post in posts[key][:10]:
                print(f\"  {post}\")
            break
    else:
        print(json.dumps(posts, indent=2)[:2000])
elif isinstance(posts, list):
    for post in posts[:10]:
        print(f\"  {post}\")
else:
    print(type(posts), str(posts)[:1000])
"

